```typescript
import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { Question, ProctorLog } from '../types';
import { EXAM_CONTEXT } from '../constants';
import Proctoring from '../components/Proctoring';
import CodeRunner from '../components/CodeRunner';
import { db } from '../services/db';
import { evaluateExam } from '../services/gemini';
import { useToast } from '../contexts/ToastContext';

interface ExamProps {
  candidateId: string;
  onFinish: () => void;
}

const withTimeout = <T,>(promise: Promise<T>, ms: number): Promise<T> => {
  return new Promise((resolve, reject) => {
      const timer = setTimeout(() => reject(new Error("Timeout")), ms);
      promise.then(
          (res) => { clearTimeout(timer); resolve(res); },
          (err) => { clearTimeout(timer); reject(err); }
      );
  });
};

type SaveStatus = 'saved' | 'saving' | 'error';

interface Section {
  name: string;
  questions: Question[];
}

const LockIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-gray-400" viewBox="0 0 20 20" fill="currentColor">
    <path fillRule="evenodd" d="M10 2a3 3 0 00-3 3v1H6a2 2 0 00-2 2v8a2 2 0 002 2h8a2 2 0 002-2V8a2 2 0 00-2-2h-1V5a3 3 0 00-3-3zm-1 4V5a1 1 0 112 0v1H9z" clipRule="evenodd" />
  </svg>
);

const Exam: React.FC<ExamProps> = ({ candidateId, onFinish }) => {
  const [questions, setQuestions] = useState<Question[]>([]);
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [proctorLogs, setProctorLogs] = useState<ProctorLog[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [saveStatus, setSaveStatus] = useState<SaveStatus>('saved');
  const [activeSection, setActiveSection] = useState<string>('');
  const { addToast } = useToast();

  const [timeRemaining, setTimeRemaining] = useState<number | null>(null);
  const totalDurationRef = useRef<number>(60);

  const sectionRefs = useRef<Record<string, HTMLElement | null>>({});

  useEffect(() => {
    const init = async () => {
      const candidate = await db.getCandidate(candidateId);
      if (!candidate || !candidate.assignedPaperId) {
        alert("Configuration Error: No exam paper assigned.");
        onFinish();
        return;
      }

      const paper = await db.getPaper(candidate.assignedPaperId);
      if (!paper) {
        alert("Configuration Error: Assigned exam paper not found.");
        onFinish();
        return;
      }
      setQuestions(paper.questions);
      setActiveSection(paper.questions[0]?.section || '');
      totalDurationRef.current = paper.duration || 60;

      const sub = await db.initSubmission(candidateId, candidate.assignedPaperId);
      if (sub) {
        setProctorLogs(sub.proctorLogs || []);
        if (sub.answers && Object.keys(sub.answers).length > 0) {
           setAnswers(sub.answers);
        } else if (candidate.email === 'alex.tester@example.com') {
           const initialAnswers = paper.questions.reduce((acc, q) => ({...acc, [q.id]: q.idealAnswerKey}), {});
           setAnswers(initialAnswers);
        }

        const elapsedSeconds = Math.floor((Date.now() - sub.startTime) / 1000);
        const remaining = (totalDurationRef.current * 60) - elapsedSeconds;
        setTimeRemaining(remaining > 0 ? remaining : 0);
      }
      setIsLoading(false);
    };
    init();
  }, [candidateId, onFinish]);

  const sections = useMemo<Section[]>(() => {
    if (!questions.length) return [];
    const sectionMap: Record<string, Question[]> = {};
    questions.forEach(q => {
      if (!sectionMap[q.section]) {
        sectionMap[q.section] = [];
      }
      sectionMap[q.section].push(q);
    });
    return Object.entries(sectionMap).map(([name, questions]) => ({ name, questions }));
  }, [questions]);

  // Determine which sections are unlocked based on answers
  const unlockedUptoIndex = useMemo(() => {
    if (!sections.length) return -1; // No sections available

    for (let i = 0; i < sections.length; i++) {
        const section = sections[i];
        const allQuestionsAnswered = section.questions.every(q => answers[q.id]?.trim());

        if (!allQuestionsAnswered) {
            // This is the first incomplete section. The user can work on this one, but no further.
            return i;
        }
    }
    // If all sections are complete, all are unlocked
    return sections.length;
  }, [sections, answers]);


  // Observer for active section highlighting
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            setActiveSection(entry.target.id);
          }
        });
      },
      { rootMargin: '-50% 0px -50% 0px', threshold: 0 }
    );

    const currentRefs = sectionRefs.current;
    Object.values(currentRefs).forEach(ref => {
      if (ref) observer.observe(ref);
    });

    return () => {
      Object.values(currentRefs).forEach(ref => {
        if (ref) observer.unobserve(ref);
      });
    };
  }, [sections]);

  useEffect(() => {
    const interval = setInterval(async () => {
      if (!Object.keys(answers).length) return;
      setSaveStatus('saving');
      try {
        await db.saveDraft(candidateId, answers, proctorLogs);
        await new Promise(res => setTimeout(res, 400));
        setSaveStatus('saved');
      } catch (e) {
        console.error("Auto-save failed", e);
        setSaveStatus('error');
      }
    }, 5000); 
    return () => clearInterval(interval);
  }, [answers, proctorLogs, candidateId]);

  useEffect(() => {
    if (timeRemaining === null || isSubmitting) return;
    if (timeRemaining <= 0) {
      handleSubmit();
      return;
    }
    const timer = setInterval(() => setTimeRemaining(prev => Math.max(0, (prev || 0) - 1)), 1000);
    return () => clearInterval(timer);
  }, [timeRemaining, isSubmitting]);

  const handleProctorViolation = useCallback((log: ProctorLog) => {
    setProctorLogs(prev => [...prev, log]);
    const message = log.type === 'TAB_SWITCH' || log.type === 'LOST_FOCUS'
      ? 'Tab switching is not allowed and has been logged.'
      : 'Copy/paste and right-clicking are disabled. This has been logged.';
    addToast(message, 'warning');
  }, [addToast]);

  const handleAnswerChange = (qId: string, text: string) => {
    setAnswers(prev => ({ ...prev, [qId]: text }));
  };

  const handleSubmit = async () => {
    if (isSubmitting) return;
    setIsSubmitting(true);
    setSaveStatus('saving');

    try {
      await db.saveDraft(candidateId, answers, proctorLogs);
      await db.submitExam(candidateId);
      try {
        const evaluation = await withTimeout(evaluateExam(questions, answers), 60000);
        await db.saveEvaluation(candidateId, evaluation);
      } catch (aiError) {
        console.error("Auto-grading skipped:", aiError);
      }
    } catch (error) {
      console.error("Submission error:", error);
    } finally {
      onFinish();
    }
  };

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return h > 0 
      ? `${h}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`
      : `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const getTimerColor = () => {
    if (timeRemaining === null) return 'text-gray-600';
    if (timeRemaining < 300) return 'text-red-600 animate-pulse';
    if (timeRemaining < 900) return 'text-yellow-600';
    return 'text-gray-800';
  };

  if (isLoading) {
    return <div className="p-8 text-center">Loading Exam Paper...</div>;
  }

  return (
    <div className="flex flex-col md:flex-row gap-8">
      <Proctoring isActive={!isSubmitting} onViolation={handleProctorViolation} />

      {/* Left Sidebar */}
      <aside className="md:w-1/4 lg:w-1/5 md:sticky md:top-24 h-fit bg-white rounded-lg shadow p-4 border">
        <h3 className="font-bold text-lg mb-4 border-b pb-2">Exam Sections</h3>
        <nav className="space-y-2">
          {sections.map((section, index) => {
            const answeredCount = section.questions.filter(q => !!answers[q.id]?.trim()).length;
            const totalCount = section.questions.length;
            const isActive = activeSection === section.name;
            const isLocked = index > unlockedUptoIndex;

            return (
              <a 
                key={section.name} 
                href={`#${section.name}`}
                onClick={(e) => {
                  e.preventDefault(); // Prevent default anchor navigation
                  if (isLocked) {
                    addToast('Please complete all questions in the previous section to proceed.', 'warning');
                  } else {
                    const el = document.getElementById(section.name);
                    if (el) {
                      el.scrollIntoView({ behavior: 'smooth' });
                      setActiveSection(section.name);
                    }
                  }
                }}
                className={`block p-3 rounded-md transition-colors text-sm ${isActive ? 'bg-brand-50 text-brand-700 font-bold' : 'hover:bg-gray-100'} ${isLocked ? 'opacity-60 cursor-not-allowed' : ''}`}
              >
                <div className="flex justify-between items-center">
                  <span className="flex items-center gap-2">
                    {isLocked && <LockIcon />}
                    {section.name}
                  </span>
                  <span className={`text-xs px-2 py-0.5 rounded-full ${isActive ? 'bg-brand-100' : 'bg-gray-200'}`}>
                    {answeredCount}/{totalCount}
                  </span>
                </div>
              </a>
            );
          })}
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 space-y-8">
        <div className="bg-blue-50 border-l-4 border-blue-500 p-4 rounded shadow-sm">
          <h3 className="text-blue-800 font-bold mb-2">Scenario Context: Pathfinder</h3>
          <p className="text-blue-900 text-sm whitespace-pre-line">{EXAM_CONTEXT}</p>
        </div>

        <div className="bg-white shadow rounded-lg p-4 flex justify-between items-center sticky top-0 z-10 border-b">
          <div className="flex items-center gap-4 text-xs font-medium">
            <span className="text-gray-600">Progress: {Object.keys(answers).filter(k => answers[k]).length} / {questions.length}</span>
            <div className="h-4 w-px bg-gray-300"></div>
            {saveStatus === 'saving' && <span className="text-brand-600 animate-pulse">Saving...</span>}
            {saveStatus === 'saved' && <span className="text-green-600">Saved</span>}
            {saveStatus === 'error' && <span className="text-red-600">Save Error</span>}
          </div>

          {timeRemaining !== null && (
            <div className={`text-xl font-bold ${getTimerColor()}`}>
                {formatTime(timeRemaining)}
            </div>
          )}

          <div className="text-red-600 font-bold text-sm flex items-center gap-2">
            {proctorLogs.length > 0 && <span>Violations: {proctorLogs.length}</span>}
          </div>
        </div>

        <div className="space-y-8">
          {sections.map((section, index) => {
            const isSectionLocked = index > unlockedUptoIndex;
            return (
            <section 
              key={section.name}
              id={section.name}
              ref={el => { sectionRefs.current[section.name] = el; }}
              className="scroll-mt-24"
            >
              <div className="flex justify-between items-center border-b-2 border-brand-500 pb-2 mb-6">
                <h2 className="text-xl font-bold text-gray-800">
                  {section.name}
                </h2>
                {isSectionLocked && <div className="flex items-center gap-2 text-sm text-gray-500 bg-gray-100 px-3 py-1 rounded-full"><LockIcon /> Locked</div>}
              </div>
              <div className="space-y-6">
                {section.questions.map(q => (
                  <div key={q.id} className="bg-white p-6 rounded-lg shadow-md border border-gray-200">
                    <h3 className="text-lg font-bold text-gray-900 mb-2">
                      {q.title} 
                      <span className="ml-2 text-sm font-normal text-gray-500">({q.marks || 10} marks)</span>
                    </h3>
                    <p className="text-gray-700 mb-4 whitespace-pre-line">{q.text}</p>

                    {q.codeType === 'javascript' ? (
                      <CodeRunner 
                        code={answers[q.id] || ''} 
                        onChange={(val) => handleAnswerChange(q.id, val)}
                        language="javascript"
                        disabled={isSectionLocked}
                      />
                    ) : (
                      <textarea
                        className="w-full h-40 p-4 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 font-sans disabled:bg-gray-100 disabled:cursor-not-allowed"
                        placeholder="Type your answer here..."
                        value={answers[q.id] || ''}
                        onChange={(e) => handleAnswerChange(q.id, e.target.value)}
                        disabled={isSectionLocked}
                      />
                    )}
                  </div>
                ))}
              </div>
            </section>
          )})}
        </div>

        <div className="flex justify-end pt-6 pb-12">
          <button
            onClick={handleSubmit}
            disabled={isSubmitting}
            type="button"
            className="bg-green-600 text-white px-8 py-3 rounded-lg font-bold text-lg hover:bg-green-700 transition-colors shadow-lg disabled:opacity-50"
          >
            {isSubmitting ? 'Submitting...' : 'Submit Final Assessment'}
          </button>
        </div>
      </main>
    </div>
  );
};

export default Exam;

