                         <span className="font-bold text-gray-700">
                            {currentQuestionIndex === -1 ? 'New Question' : `Question ${currentQuestionIndex + 1} of ${questions.length}`}
                         </span>
                         {questions.length > 0 && (
                            <select className="text-xs border rounded p-1 max-w-[150px]" value={currentQuestionIndex} onChange={(e) => handleJumpToQuestion(parseInt(e.target.value))}>
                                <option value={-1}>-- New Question --</option>
                                {questions.map((q, i) => (
