                         <button onClick={handleNextQuestion} className="text-xs px-3 py-1 rounded bg-brand-600 text-white hover:bg-brand-700">
                            {currentQuestionIndex === -1 || currentQuestionIndex === questions.length - 1 ? 'Add & Next' : 'Next →'}
                         </button>
