  // Handle Syntax Highlighting for Input based on selectedLanguage
  useEffect(() => {
    if (typeof Prism !== 'undefined') {
      let langClass = selectedLanguage.toLowerCase();
      // Map basic names to Prism classes if needed
      if (langClass === 'c++') langClass = 'cpp';
      if (langClass === 'c#') langClass = 'csharp';
      if (langClass.includes('selenium') || langClass === 'junit') langClass = 'java';
      if (langClass === 'selenium_python') langClass = 'python';
      if (langClass === 'cypress' || langClass === 'playwright') langClass = 'javascript';
      if (langClass === 'docker') langClass = 'docker';
      if (langClass === 'kubernetes' || langClass === 'ansible') langClass = 'yaml';
      if (langClass === 'terraform') langClass = 'hcl';

      // Default to generic 'clike' or 'javascript' if grammar not found
      const grammar = Prism.languages[langClass] || Prism.languages.javascript;

      if (grammar) {
        const html = Prism.highlight(code || '', grammar, langClass);
        setHighlightedCode(html);
      } else {
        setHighlightedCode(code.replace(/</g, "&lt;").replace(/>/g, "&gt;"));
      }
