        await db.saveEvaluation(submission.candidateId, result);
        await fetchData();
      } else {
        alert("Original question paper for this submission not found.");
      }
    } catch (e) {
      console.error("Evaluation failed", e);
    } finally {
      setEvaluatingId(null);
    }
  };

  // --- CSV Import Logic ---

  const handleDownloadTemplate = () => {
    // Create a CSV template with 20 rows: 10 Aptitude + 10 Technical
    let csvContent = "data:text/csv;charset=utf-8,Section,Title,QuestionText,IdealAnswer,Type(text/script),Marks\n";

    // First 10: Aptitude
    for (let i = 1; i <= 10; i++) {
        csvContent += `Aptitude & Reasoning,Aptitude Q${i},Enter question text here...,The answer is...,text,5\n`;
    }
    // Next 10: Technical
    for (let i = 1; i <= 10; i++) {
        csvContent += `Technical Assessment,Technical Q${i},Write a function that...,def function():...,script,10\n`;
    }

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "exam_template_20q.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleImportCSV = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
        const text = e.target?.result as string;
        if (!text) return;

        try {
            const rows = text.split('\n');
            const header = rows[0].toLowerCase();
            const headerCols = header.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g)?.map(h => h.replace(/^"|"$/g, '').trim()) || header.split(',').map(h => h.trim());

            const colMap: Record<string, number> = {};
            headerCols.forEach((col, idx) => {
                if (col === 'id') colMap['id'] = idx;
                if (col.includes('section')) colMap['section'] = idx;
                if (col.includes('title')) colMap['title'] = idx;
                if (col.includes('questiontext') || col.includes('question text')) colMap['text'] = idx;
                if (col.includes('ideal') || col.includes('answer')) colMap['answer'] = idx;
                if (col.includes('type')) colMap['type'] = idx;
                if (col.includes('mark')) colMap['marks'] = idx;
            });

            const newQuestions: Question[] = [];
            const updatedQuestionsMap = new Map<string, Question>();
            const existingQuestionsMap = new Map(questions.map(q => [q.id, q]));

            const dataRows = rows.slice(1).filter(r => r.trim() !== '');

            dataRows.forEach((row, index) => {
                const cols = row.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g) || row.split(',');
                const clean = (str: string | undefined) => str ? str.replace(/^"|"$/g, '').replace(/""/g, '"').trim() : '';
                const getVal = (key: string, fallbackIdx: number) => {
                    if (colMap[key] !== undefined && cols[colMap[key]]) return clean(cols[colMap[key]]);
                    if (Object.keys(colMap).length < 3 && cols[fallbackIdx]) return clean(cols[fallbackIdx]);
                    return '';
                };

                let idVal = '';
                let fallbackOffset = 0;

                if (colMap['id'] !== undefined) {
                    idVal = clean(cols[colMap['id']]);
                } else if (cols.length >= 7 && header.startsWith('id')) {
                    idVal = clean(cols[0]);
                    fallbackOffset = 1;
                }

                let section = getVal('section', 0 + fallbackOffset);
                const title = getVal('title', 1 + fallbackOffset) || `Question`;
                const qText = getVal('text', 2 + fallbackOffset);
                const idealAnswer = getVal('answer', 3 + fallbackOffset);
                let type = clean(getVal('type', 4 + fallbackOffset)).toLowerCase() || 'text';
                const marks = parseInt(getVal('marks', 5 + fallbackOffset)) || 5;

                if (index < 10 && !section) {
                    section = "Aptitude & Reasoning";
                    if (type !== 'text') type = 'text'; 
                } else if (index < 20 && !section) {
                    section = "Technical Assessment";
                } else if (!section) {
                    section = "Technical Assessment";
                }

                if (qText) {
                    const qObj: Question = {
                        id: idVal || `q-csv-${Date.now()}-${index}`,
                        section: section,
                        title: title,
                        text: qText,
                        idealAnswerKey: idealAnswer,
                        codeType: type,
                        marks: marks
                    };

                    if (idVal && existingQuestionsMap.has(idVal)) {
                        updatedQuestionsMap.set(idVal, qObj);
                    } else {
                        newQuestions.push(qObj);
                    }
                }
            });

            let finalQs: Question[] = [];
            let updateCount = 0;
            let addCount = 0;

            if (updatedQuestionsMap.size > 0) {
                finalQs = questions.map(q => updatedQuestionsMap.has(q.id) ? updatedQuestionsMap.get(q.id)! : q);
                finalQs = [...finalQs, ...newQuestions];
                updateCount = updatedQuestionsMap.size;
                addCount = newQuestions.length;
            } else {
                finalQs = [...questions, ...newQuestions];
                addCount = newQuestions.length;
            }

            if (finalQs.length > 0) {
                setQuestions(finalQs);
                alert(`Import Complete:\n- Updated: ${updateCount} questions\n- Added: ${addCount} questions`);
                if (finalQs.length > 0) setCurrentQuestionIndex(0);
                if (fileInputRef.current) fileInputRef.current.value = '';
            } else {
                alert("No valid questions found in CSV.");
            }
        } catch (err) {
            console.error("CSV Parse Error", err);
            alert("Failed to parse CSV. Please ensure it matches the template format.");
        }
    };
    reader.readAsText(file);
  };

  // --- Paper Editor Logic ---

  const initPaperEditor = (paper?: QuestionPaper) => {
    if (paper) {
        setEditingPaperId(paper.id);
        setPaperTitle(paper.title);
        setPaperDesc(paper.description);
        setPaperDuration(paper.duration || 60);
        setQuestions([...paper.questions]);
        if (paper.questions.length > 0) {
            loadQuestionIntoForm(paper.questions[0], 0);
        } else {
            setCurrentQuestionIndex(-1); // New Q state
            clearQuestionForm();
        }
    } else {
        setEditingPaperId(null);
        setPaperTitle('');
        setPaperDesc('');
        setPaperDuration(60);
        setQuestions([]);
        setCurrentQuestionIndex(-1);
        clearQuestionForm();
    }
  };

  const clearQuestionForm = () => {
    setQId(`q-${Date.now()}`);
    setQTitle(''); setQText(''); setQKey(''); setQType('text'); setQMarks('10');
    setQSection('Technical Assessment');
  };

  const loadQuestionIntoForm = (q: Question, index: number) => {
    setCurrentQuestionIndex(index);
    setQId(q.id);
    setQTitle(q.title);
    setQText(q.text);
    setQType(q.codeType || 'text');
    setQMarks(String(q.marks || 10));
    setQKey(q.idealAnswerKey);
    setQSection(q.section);
  };

  // Saves the CURRENT form data into the questions array at the current index
  const commitCurrentQuestion = () => {
      // Validate
      if (!qTitle.trim() || !qText.trim()) return false;

      const newQ: Question = {
          id: qId,
          section: qSection,
          title: qTitle,
          text: qText,
          codeType: qType,
          marks: parseInt(qMarks) || 10,
          idealAnswerKey: qKey
      };

      const updatedQuestions = [...questions];

      if (currentQuestionIndex === -1 || currentQuestionIndex >= questions.length) {
          // It's a new question
          updatedQuestions.push(newQ);
          setQuestions(updatedQuestions);
          setCurrentQuestionIndex(updatedQuestions.length - 1); // Move to this new index
      } else {
          // Update existing
          updatedQuestions[currentQuestionIndex] = newQ;
          setQuestions(updatedQuestions);
      }
      return true;
  };

  const handleNextQuestion = () => {
      if (!commitCurrentQuestion()) {
          alert("Please fill in the title and text before proceeding.");
          return;
      }

      const nextIndex = currentQuestionIndex + 1;
      if (nextIndex < questions.length) {
          loadQuestionIntoForm(questions[nextIndex], nextIndex);
      } else {
          // Move to "Add New" state
          setCurrentQuestionIndex(-1);
          clearQuestionForm();
      }
  };

  const handlePrevQuestion = () => {
      commitCurrentQuestion(); // Save progress on current
      const prevIndex = currentQuestionIndex === -1 ? questions.length - 1 : currentQuestionIndex - 1;
      if (prevIndex >= 0) {
          loadQuestionIntoForm(questions[prevIndex], prevIndex);
      }
  };

  const handleJumpToQuestion = (index: number) => {
      commitCurrentQuestion();
      if (index >= 0 && index < questions.length) {
          loadQuestionIntoForm(questions[index], index);
      }
  };

  const handleAddNewQuestion = () => {
      commitCurrentQuestion();
      setCurrentQuestionIndex(-1);
      clearQuestionForm();
  };

  const handleRemoveCurrentQuestion = () => {
      if (currentQuestionIndex >= 0 && currentQuestionIndex < questions.length) {
          const newQs = questions.filter((_, i) => i !== currentQuestionIndex);
          setQuestions(newQs);

          if (newQs.length > 0) {
              const newIndex = Math.min(currentQuestionIndex, newQs.length - 1);
              loadQuestionIntoForm(newQs[newIndex], newIndex);
          } else {
              setCurrentQuestionIndex(-1);
              clearQuestionForm();
          }
      }
  };

  const handleSavePaper = async () => {
    // Commit any unsaved changes in the form
    if (qTitle.trim() && qText.trim()) {
        commitCurrentQuestion();
    }

    await new Promise(r => setTimeout(r, 100));

    if (!paperTitle) {
        alert("Please provide a paper title.");
        return;
    }

    let finalQuestions = [...questions];

    // Check pending form
    if (qTitle.trim() && qText.trim()) {
        const currentFormQ: Question = {
            id: qId, section: qSection, title: qTitle, text: qText, codeType: qType, marks: parseInt(qMarks) || 10, idealAnswerKey: qKey
        };
        if (currentQuestionIndex === -1) {
             finalQuestions.push(currentFormQ);
        } else {
             finalQuestions[currentQuestionIndex] = currentFormQ;
        }
    }

    if (finalQuestions.length === 0) {
        alert("Please add at least one question.");
        return;
    }

    const paper: QuestionPaper = {
      id: editingPaperId || `paper-${Date.now()}`,
      title: paperTitle,
      description: paperDesc,
      questions: finalQuestions,
      duration: paperDuration,
      createdAt: editingPaperId ? (papers.find(p => p.id === editingPaperId)?.createdAt || Date.now()) : Date.now()
    };

    if (editingPaperId) {
        await db.updateQuestionPaper(paper);
    } else {
        await db.createQuestionPaper(paper);
    }

    alert("Exam Paper Saved!");
    initPaperEditor(undefined); // Reset
    fetchData();
  };

