      if (langClass === 'c++') langClass = 'cpp';
      if (langClass === 'c#') langClass = 'csharp';

      // QA Mappings
      if (langClass === 'selenium_java' || langClass === 'junit') langClass = 'java';
      if (langClass === 'selenium_python') langClass = 'python';
      if (langClass === 'cypress' || langClass === 'playwright') langClass = 'javascript';
      if (langClass === 'cucumber') langClass = 'gherkin'; // Requires gherkin prism component
      if (langClass === 'postman') langClass = 'json';

      // DevOps Mappings
      if (langClass === 'docker') langClass = 'docker';
      if (langClass === 'kubernetes' || langClass === 'ansible') langClass = 'yaml';
      if (langClass === 'terraform') langClass = 'hcl'; // Terraform uses HCL
      if (langClass === 'jenkins') langClass = 'groovy';
      if (langClass === 'bash') langClass = 'bash';

      // Default to generic 'clike' or 'javascript' if grammar not found
      // If specialized grammar (like docker) is missing, it falls back to plain text often, 
      // but we can try to fallback to clike for basic coloring.
      const grammar = Prism.languages[langClass] || Prism.languages.javascript;

      if (grammar) {
        const html = Prism.highlight(code || '', grammar, langClass);
        setHighlightedCode(html);
      } else {
        setHighlightedCode(code.replace(/</g, "&lt;").replace(/>/g, "&gt;"));
      }
    } else {
      // Fallback if not a code language or Prism missing
      setHighlightedCode(code.replace(/</g, "&lt;").replace(/>/g, "&gt;"));
    }
  }, [code, selectedLanguage]);

  // Sync scroll between textarea and pre
  const handleScroll = (e: React.UIEvent<HTMLTextAreaElement>) => {
    if (preRef.current) {
      preRef.current.scrollTop = e.currentTarget.scrollTop;
      preRef.current.scrollLeft = e.currentTarget.scrollLeft;
    }
  };

  const handleRunCode = async () => {
    // If user selected JS, we can run locally. 
    // Otherwise use AI executor.
    if (selectedLanguage === 'javascript') {
        runJsLocally();
    } else {
        runWithAI();
    }
  };

  const runWithAI = async () => {
    setIsChecking(true);
    setOutput(null);
    setError(null);
    try {
      const result = await executeCodeWithAI(code, selectedLanguage);
      if (result.type === 'error') {
        setError(result.content);
      } else { // 'output'
        const outputContent = result.content.trim() === '' 
          ? `// ${selectedLanguage} code executed successfully with no output.`
          : result.content;
        setOutput(outputContent);
      }
    } catch(e: any) {
      setError(e.toString());
    } finally {
      setIsChecking(false);
    }
  };

  const runJsLocally = () => {
    setOutput(null);
    setError(null);

    const logs: string[] = [];
    const originalConsoleLog = console.log;

    // Intercept console.log
    console.log = (...args: any[]) => {
      logs.push(args.map(a => {
        if (typeof a === 'object') return JSON.stringify(a, null, 2);
        return String(a);
      }).join(' '));
    };

    try {
      // Execute unsafe code safely in a minimal scope
      // eslint-disable-next-line no-new-func
      const run = new Function(code);
      const result = run();

      if (result !== undefined) {
        if (typeof result === 'object') {
            logs.push(`> Return Value:\n${JSON.stringify(result, null, 2)}`);
        } else {
            logs.push(`> Return Value: ${String(result)}`);
        }
      }

      if (logs.length === 0) {
        logs.push("// Code executed successfully (No output).\n// Use console.log() to see results.");
      }

      setOutput(logs.join('\n'));
    } catch (e: any) {
      setError(e.toString());
    } finally {
      // Restore console.log
      console.log = originalConsoleLog;
    }
  };

  // Helper to highlight output logs (basic JSON highlighting)
  const getHighlightedOutput = (text: string) => {
    if (typeof Prism !== 'undefined') {
       const grammar = (text.trim().startsWith('{') || text.trim().startsWith('[')) 
          ? Prism.languages.json 
          : Prism.languages.javascript;

       return Prism.highlight(text, grammar, 'javascript');
    }
    return text;
  };

  const getFileName = () => {
      // Standard Langs
      if (selectedLanguage === 'javascript') return 'main.js';
      if (selectedLanguage === 'python') return 'script.py';
      if (selectedLanguage === 'java') return 'Main.java';
      if (selectedLanguage === 'cpp') return 'main.cpp';
      if (selectedLanguage === 'csharp') return 'Program.cs';
      if (selectedLanguage === 'sql') return 'query.sql';

      // QA Tools
