      if (selectedLanguage.includes('selenium_python')) return 'selenium_test.py';
      if (selectedLanguage === 'cypress') return 'spec.cy.js';
      if (selectedLanguage === 'playwright') return 'test.spec.ts';
      if (selectedLanguage === 'cucumber') return 'features.feature';
      if (selectedLanguage === 'postman') return 'collection.json';

      // DevOps Tools
      if (selectedLanguage === 'docker') return 'Dockerfile';
      if (selectedLanguage === 'kubernetes') return 'deployment.yaml';
      if (selectedLanguage === 'terraform') return 'main.tf';
      if (selectedLanguage === 'ansible') return 'playbook.yaml';
      if (selectedLanguage === 'bash') return 'script.sh';
      if (selectedLanguage === 'jenkins') return 'Jenkinsfile';

      return `script.${selectedLanguage.slice(0, 3)}`;
  }

  const getButtonContent = () => {
    if (selectedLanguage !== 'javascript') {
      return isChecking ? 'Checking...' : `Check Code`;
    }
    return 'Run (JS)';
  };

  return (
    <div className="border border-gray-300 rounded-md overflow-hidden bg-[#2d2d2d] text-white shadow-sm flex flex-col h-[500px]">
      {/* Toolbar */}
      <div className="flex justify-between items-center bg-[#1f1f1f] px-4 py-2 border-b border-gray-700 shrink-0">
        <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
                <span className="w-3 h-3 rounded-full bg-red-500"></span>
                <span className="w-3 h-3 rounded-full bg-yellow-500"></span>
                <span className="w-3 h-3 rounded-full bg-green-500"></span>
            </div>

            {/* Language Selector */}
            <select 
                value={selectedLanguage} 
                onChange={(e) => setSelectedLanguage(e.target.value)}
                className="bg-[#2d2d2d] text-gray-300 text-xs border border-gray-600 rounded px-2 py-1 outline-none focus:border-brand-500 max-w-[200px]"
            >
                {SUPPORTED_LANGUAGES.map(lang => (
