          <h2 className="text-xl font-semibold text-gray-700">Starting System...</h2>
        </div>
      </div>
    );
  }

  return (
    <ToastProvider>
      <Layout 
        user={currentUser ? { name: currentUser.fullName } : undefined} 
        onLogout={handleLogout}
        isAdmin={isAdmin}
      >
        {renderContent()}
      </Layout>
    </ToastProvider>
  );
};

export default App;
