      const candidate = await db.getCandidate(candidateId);
      if (!candidate || !candidate.assignedPaperId) {
        alert("Configuration Error: No exam paper assigned.");
        onFinish();
        return;
      }

      // Fetch the actual question paper
      const paper = await db.getPaper(candidate.assignedPaperId);
      if (!paper) {
        alert("Configuration Error: Assigned exam paper not found.");
        onFinish();
        return;
      }
      setQuestions(paper.questions);
      setPaperDescription(paper.description);
      totalDurationRef.current = paper.duration || 90;

      // Load or Initialize Submission
      const sub = await db.initSubmission(candidateId, candidate.assignedPaperId);
      if (sub) {
        if (sub.proctorLogs && sub.proctorLogs.length > 0) {
          setProctorLogs(sub.proctorLogs);
        }

        // If there's a saved draft, load it.
        if (sub.answers && Object.keys(sub.answers).length > 0) {
           setAnswers(sub.answers);
        }

        // Calculate Time Remaining
        const now = Date.now();
        const elapsedSeconds = Math.floor((now - sub.startTime) / 1000);
        const totalSeconds = totalDurationRef.current * 60;
        const remaining = totalSeconds - elapsedSeconds;
        setTimeRemaining(remaining > 0 ? remaining : 0);
      }
      setIsLoading(false);
    };
    init();
  }, [candidateId, onFinish]);

  // Periodic Auto-save
  useEffect(() => {
    const interval = setInterval(async () => {
      if (Object.keys(answers).length === 0) return;

      setSaveStatus('saving');
      try {
        await db.saveDraft(candidateId, answers, proctorLogs);
        await new Promise(resolve => setTimeout(resolve, 400));
        setSaveStatus('saved');
      } catch (e) {
        console.error("Auto-save failed", e);
        setSaveStatus('error');
      }
    }, 5000); 
    return () => clearInterval(interval);
  }, [answers, proctorLogs, candidateId]);

  // Timer Countdown Logic
  useEffect(() => {
    if (timeRemaining === null || isSubmitting) return;

    if (timeRemaining <= 0) {
        // Time is up!
        handleSubmit();
        return;
    }

    const timer = setInterval(() => {
        setTimeRemaining(prev => (prev !== null && prev > 0 ? prev - 1 : 0));
    }, 1000);

    return () => clearInterval(timer);
  }, [timeRemaining, isSubmitting]);

  const handleProctorViolation = useCallback((log: ProctorLog) => {
    setProctorLogs(prev => [...prev, log]);

    // Determine message based on log type
    let message = '';
    switch(log.type) {
        case 'TAB_SWITCH':
            message = 'Warning: Tab switching is monitored.';
            break;
        case 'COPY_ATTEMPT':
            message = 'Warning: Copying content is disabled.';
            break;
        case 'PASTE_ATTEMPT':
            message = 'Warning: Pasting content is disabled.';
            break;
        case 'CONTEXT_MENU':
            message = 'Warning: Right-click menu is disabled.';
            break;
        case 'LOST_FOCUS':
            message = 'Warning: Please keep the exam window in focus.';
            break;
    }

    if (message) {
        addToast(message, 'warning', 4000);
    }
  }, [addToast]);

  const handleAnswerChange = (qId: string, text: string) => {
    setAnswers(prev => ({ ...prev, [qId]: text }));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    setSaveStatus('saving');

    try {
      await db.saveDraft(candidateId, answers, proctorLogs);
      await db.submitExam(candidateId);

      try {
        // Pass the paper description as context for grading
        const evaluation = await withTimeout(evaluateExam(questions, answers, paperDescription), 60000);
        await db.saveEvaluation(candidateId, evaluation);
      } catch (aiError) {
        console.error("Auto-grading skipped due to timeout:", aiError);
      }

    } catch (error) {
      console.error("Error during submission process:", error);
    } finally {
      onFinish();
    }
  };

  const renderSaveStatus = () => {
    switch (saveStatus) {
      case 'saving':
        return <span className="text-xs font-medium text-brand-600">Saving...</span>;
      case 'error':
        return <span className="text-xs font-medium text-red-600">Save Error</span>;
      case 'saved':
      default:
        return <span className="text-xs font-medium text-green-600">Saved</span>;
    }
  };

  const formatTime = (seconds: number) => {
      const h = Math.floor(seconds / 3600);
      const m = Math.floor((seconds % 3600) / 60);
      const s = seconds % 60;
      if (h > 0) return `${h}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
      return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const getTimerColor = () => {
      if (timeRemaining === null) return 'text-gray-600';
      if (timeRemaining < 300) return 'text-red-600 animate-pulse font-bold';
      if (timeRemaining < 900) return 'text-yellow-600 font-bold';
      return 'text-gray-800 font-bold';
  };

  // Group questions by section
  const groupedQuestions = useMemo(() => {
    return questions.reduce((acc, q) => {
      if (!acc[q.section]) acc[q.section] = [];
      acc[q.section].push(q);
      return acc;
    }, {} as Record<string, Question[]>);
  }, [questions]);

  let globalQuestionIndex = 0;

  if (isLoading) {
      return <div className="p-8 text-center">Loading Exam Paper...</div>;
  }

  return (
    <div className="space-y-6">
      <Proctoring isActive={!isSubmitting} onViolation={handleProctorViolation} />

      <div className="bg-blue-50 border-l-4 border-blue-500 p-4 rounded shadow-sm">
        <h3 className="text-blue-800 font-bold mb-2">Scenario Context</h3>
        <p className="text-blue-900 text-sm whitespace-pre-line">{paperDescription || 'No description provided.'}</p>
      </div>

      <div className="bg-white shadow rounded-lg p-4 flex justify-between items-center sticky top-0 z-10 border-b">
        <div className="flex items-center gap-6">
            <span className="text-gray-600 font-medium">Progress: {Object.keys(answers).filter(k => answers[k].trim()).length} / {questions.length} Answered</span>
            <div className="h-6 w-px bg-gray-300"></div>
            {renderSaveStatus()}
        </div>

        {timeRemaining !== null && (
            <div className={`text-xl bg-gray-100 px-4 py-1 rounded border ${getTimerColor()}`}>
                Time Left: {formatTime(timeRemaining)}
            </div>
        )}

        <div className="text-red-600 font-bold text-sm flex items-center gap-2">
            {proctorLogs.length > 0 && <span>Violations: {proctorLogs.length}</span>}
        </div>
      </div>

      <div className="space-y-10">
        {Object.entries(groupedQuestions).map(([sectionName, qs]) => {
          const sectionQs = qs as Question[];
          return (
            <div key={sectionName}>
              <div className="flex items-center gap-4 mb-4">
                <h2 className="text-2xl font-bold text-gray-800">{sectionName}</h2>
                <div className="h-1 flex-grow bg-gray-200 rounded"></div>
              </div>

              <div className="space-y-6">
                {sectionQs.map((q) => {
                  globalQuestionIndex++;
                  const isCoding = q.codeType && q.codeType !== 'text';

                  return (
                    <div key={q.id} className="bg-white p-6 rounded-lg shadow-md border border-gray-200">

                      {/* NEW DISPLAY FORMAT: Q1. Text... (10 marks) */}
                      <div className="mb-4">
                        <p className="text-lg text-gray-800 whitespace-pre-line leading-relaxed">
                            <span className="font-bold text-brand-700 mr-2 select-none">Q{globalQuestionIndex}.</span>
                            {q.text}
                            <span className="inline-block text-sm font-bold text-gray-500 bg-gray-100 px-2 py-0.5 rounded ml-2 align-middle">
                                ({q.marks || 10} Marks)
                            </span>
                        </p>
                      </div>

                      {isCoding ? (
                        <CodeRunner 
                          code={answers[q.id] || ''} 
                          onChange={(val) => handleAnswerChange(q.id, val)}
                          language={q.codeType === 'script' ? 'javascript' : (q.codeType || 'javascript')}
                        />
                      ) : (
                        <textarea
                          className="w-full h-40 p-4 border border-gray-300 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-brand-500 font-sans text-base leading-relaxed text-gray-800 resize-y"
                          placeholder="Type your answer here..."
                          value={answers[q.id] || ''}
                          onChange={(e) => handleAnswerChange(q.id, e.target.value)}
                          spellCheck={false}
                        />
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>

      <div className="flex justify-end pt-6 pb-12">
        <button
          onClick={handleSubmit}
          disabled={isSubmitting}
          type="button"
          className="bg-green-600 text-white px-8 py-3 rounded-lg font-bold text-lg hover:bg-green-700 transition-colors shadow-lg disabled:opacity-50 flex items-center gap-2"
        >
          {isSubmitting ? 'Grading Assessment...' : 'Submit Assessment'}
        </button>
      </div>
    </div>
  );
};

export default Exam;
