```typescript
import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Candidate, ExamSubmission, QuestionPaper, Question, ExamAssignment } from '../types';
import { db } from '../services/db';
import { evaluateExam } from '../services/gemini';

declare const Prism: any;

const IdealAnswerViewer: React.FC<{ question: Question }> = ({ question }) => {
    const { idealAnswerKey, codeType } = question;
    const highlightedHtml = useMemo(() => {
        let lang = codeType || 'javascript';
        if (lang === 'c++') lang = 'cpp';
        if (typeof Prism !== 'undefined' && codeType && codeType !== 'text' && Prism.languages[lang]) {
            return Prism.highlight(idealAnswerKey.trim(), Prism.languages[lang], lang);
        }
        return idealAnswerKey.replace(/</g, "&lt;").replace(/>/g, "&gt;");
    }, [idealAnswerKey, codeType]);

    if (codeType && codeType !== 'text') {
        return (
            <div className="bg-gray-800 text-white rounded text-xs font-mono overflow-x-auto max-h-60">
                <pre className="p-3"><code className={`language-${codeType === 'c++' ? 'cpp' : codeType}`} dangerouslySetInnerHTML={{ __html: highlightedHtml }} /></pre>
            </div>
        );
    }
    return <p className="whitespace-pre-wrap text-gray-700 text-xs">{idealAnswerKey}</p>;
}

type AdminTab = 'SUBMISSIONS' | 'MANAGE_EXAMS' | 'ASSIGN_EXAMS';

const Admin: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AdminTab>('SUBMISSIONS');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [candidates, setCandidates] = useState<Candidate[]>([]);
  const [submissions, setSubmissions] = useState<ExamSubmission[]>([]);
  const [papers, setPapers] = useState<QuestionPaper[]>([]);
  const [assignments, setAssignments] = useState<ExamAssignment[]>([]);

  const [selectedCandidateId, setSelectedCandidateId] = useState<string | null>(null);
  const [evaluatingId, setEvaluatingId] = useState<string | null>(null);

  const [editingPaperId, setEditingPaperId] = useState<string | null>(null);
  const [paperTitle, setPaperTitle] = useState('');
  const [paperDesc, setPaperDesc] = useState('');
  const [paperDuration, setPaperDuration] = useState(60);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(-1);

  const [qId, setQId] = useState('');
  const [qTitle, setQTitle] = useState('');
  const [qText, setQText] = useState('');
  const [qType, setQType] = useState<string>('text');
  const [qMarks, setQMarks] = useState('10');
  const [qKey, setQKey] = useState('');
  const [qSection, setQSection] = useState('Technical Assessment');

  const [assignEmail, setAssignEmail] = useState('');
  const [assignPaperId, setAssignPaperId] = useState('');
  const [assignStatus, setAssignStatus] = useState('');

  const fetchData = async () => {
    const [c, p, a, s] = await Promise.all([
      db.getAllCandidates(),
      db.getAllPapers(),
      db.getAllAssignments(),
      db.getAllSubmissions()
    ]);
    setCandidates(c); setPapers(p); setAssignments(a); setSubmissions(s);
  };

  useEffect(() => { fetchData(); }, []);

  const handleDeleteCandidate = async (id: string, name: string) => {
    if (window.confirm(`Delete user ${name}?`)) { await db.deleteCandidate(id); await fetchData(); }
  };

  const handleResetSubmission = async (candidateId: string, name: string) => {
    if (window.confirm(`Reset submission for ${name}?`)) {
        await db.deleteSubmission(candidateId);
        await fetchData();
        if (selectedCandidateId === candidateId) setSelectedCandidateId(null);
    }
  };

  const handleDeletePaper = async (id: string, title: string) => {
    if (window.confirm(`Delete exam paper "${title}"?`)) {
        await db.deleteQuestionPaper(id);
        if (editingPaperId === id) initPaperEditor();
        await fetchData();
    }
  };

  const handleDeleteAssignment = async (id: string, email: string) => {
    if (window.confirm(`Delete assignment for ${email}?`)) { await db.deleteAssignment(id); await fetchData(); }
  };

  const handleExportPaper = (paper: QuestionPaper) => {
    let csvContent = "data:text/csv;charset=utf-8,ID,Section,Title,QuestionText,IdealAnswer,Type,Marks\n";
    paper.questions.forEach(q => {
        const safe = (str: string) => `"${(str || '').replace(/"/g, '""')}"`;
        const row = [safe(q.id), safe(q.section), safe(q.title), safe(q.text), safe(q.idealAnswerKey), safe(q.codeType || 'text'), q.marks || 10].join(",");
        csvContent += row + "\n";
    });
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `${paper.title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_export.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleEvaluate = async (submission: ExamSubmission) => {
    setEvaluatingId(submission.candidateId);
    try {
      const paper = await db.getPaper(submission.paperId);
      if (paper) {
        const result = await evaluateExam(paper.questions, submission.answers, paper.description);
        await db.saveEvaluation(submission.candidateId, result);
        await fetchData();
      } else { alert("Original question paper not found."); }
    } catch (e) { console.error("Evaluation failed", e); } 
    finally { setEvaluatingId(null); }
  };

  const handleDownloadTemplate = () => {
    let csvContent = "data:text/csv;charset=utf-8,Section,Title,QuestionText,IdealAnswer,Type(text/script),Marks\n";
    for (let i = 1; i <= 10; i++) csvContent += `Aptitude & Reasoning,Aptitude Q${i},Enter question text here...,The answer is...,text,5\n`;
    for (let i = 1; i <= 10; i++) csvContent += `Technical Assessment,Technical Q${i},Write a function that...,def function():...,script,10\n`;
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "exam_template_10apt_10tech.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleImportCSV = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
        const text = e.target?.result as string;
        if (!text) return;
        try {
            const rows = text.split('\n');
            const header = rows[0].toLowerCase();
            const headerCols = header.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g)?.map(h => h.replace(/^"|"$/g, '').trim()) || header.split(',').map(h => h.trim());
            const colMap: Record<string, number> = {};
            headerCols.forEach((col, idx) => {
                if (col === 'id') colMap['id'] = idx;
                if (col.includes('section')) colMap['section'] = idx;
                if (col.includes('title')) colMap['title'] = idx;
                if (col.includes('questiontext') || col.includes('question text')) colMap['text'] = idx;
                if (col.includes('ideal') || col.includes('answer')) colMap['answer'] = idx;
                if (col.includes('type')) colMap['type'] = idx;
                if (col.includes('mark')) colMap['marks'] = idx;
            });

            const newQuestions: Question[] = [];
            const updatedQuestionsMap = new Map<string, Question>();
            const existingQuestionsMap = new Map(questions.map(q => [q.id, q]));
            const dataRows = rows.slice(1).filter(r => r.trim() !== '');

            dataRows.forEach((row, index) => {
                const cols = row.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g) || row.split(',');
                const clean = (str: string | undefined) => str ? str.replace(/^"|"$/g, '').replace(/""/g, '"').trim() : '';
                const getVal = (key: string, fallbackIdx: number) => {
                    if (colMap[key] !== undefined && cols[colMap[key]]) return clean(cols[colMap[key]]);
                    if (Object.keys(colMap).length < 3 && cols[fallbackIdx]) return clean(cols[fallbackIdx]);
                    return '';
                };

                let idVal = '';
                if (colMap['id'] !== undefined) idVal = clean(cols[colMap['id']]);
                else if (cols.length >= 7 && header.startsWith('id')) idVal = clean(cols[0]);

                let section = getVal('section', 0);
                const title = getVal('title', 1) || `Question`;
                const qText = getVal('text', 2);
                const idealAnswer = getVal('answer', 3);
                let type = clean(getVal('type', 4)).toLowerCase() || 'text';
                const marks = parseInt(getVal('marks', 5)) || 5;

                if (index < 10 && !section) { section = "Aptitude & Reasoning"; if (type !== 'text') type = 'text'; } 
                else if (index < 20 && !section) { section = "Technical Assessment"; } 
                else if (!section) { section = "Technical Assessment"; }

                if (qText) {
                    const qObj: Question = {
                        id: idVal || `q-csv-${Date.now()}-${index}`,
                        section: section,
                        title: title,
                        text: qText,
                        idealAnswerKey: idealAnswer,
                        codeType: type,
                        marks: marks
                    };
                    if (idVal && existingQuestionsMap.has(idVal)) updatedQuestionsMap.set(idVal, qObj);
                    else newQuestions.push(qObj);
                }
            });

            let finalQs: Question[] = [];
            let updateCount = 0;
            let addCount = 0;

            if (updatedQuestionsMap.size > 0) {
                finalQs = questions.map(q => updatedQuestionsMap.has(q.id) ? updatedQuestionsMap.get(q.id)! : q);
                finalQs = [...finalQs, ...newQuestions];
                updateCount = updatedQuestionsMap.size;
                addCount = newQuestions.length;
            } else {
                finalQs = [...questions, ...newQuestions];
                addCount = newQuestions.length;
            }

            if (finalQs.length > 0) {
                setQuestions(finalQs);
                alert(`Import Complete:\n- Updated: ${updateCount}\n- Added: ${addCount}`);
                if (finalQs.length > 0) setCurrentQuestionIndex(0);
                if (fileInputRef.current) fileInputRef.current.value = '';
            } else {
                alert("No valid questions found in CSV.");
            }
        } catch (err) {
            console.error("CSV Parse Error", err);
            alert("Failed to parse CSV.");
        }
    };
    reader.readAsText(file);
  };

  const initPaperEditor = (paper?: QuestionPaper) => {
    if (paper) {
        setEditingPaperId(paper.id);
        setPaperTitle(paper.title);
        setPaperDesc(paper.description);
        setPaperDuration(paper.duration || 60);
        setQuestions([...paper.questions]);
        if (paper.questions.length > 0) loadQuestionIntoForm(paper.questions[0], 0);
        else { setCurrentQuestionIndex(-1); clearQuestionForm(); }
    } else {
        setEditingPaperId(null); setPaperTitle(''); setPaperDesc(''); setPaperDuration(60); setQuestions([]); setCurrentQuestionIndex(-1); clearQuestionForm();
    }
  };

  const clearQuestionForm = () => {
    setQId(`q-${Date.now()}`); setQTitle(''); setQText(''); setQKey(''); setQType('text'); setQMarks('10'); setQSection('Technical Assessment');
  };

  const loadQuestionIntoForm = (q: Question, index: number) => {
    setCurrentQuestionIndex(index);
    setQId(q.id); setQTitle(q.title); setQText(q.text); setQType(q.codeType || 'text'); setQMarks(String(q.marks || 10)); setQKey(q.idealAnswerKey); setQSection(q.section);
  };

  const commitCurrentQuestion = () => {
      if (!qTitle.trim() || !qText.trim()) return false;
      const newQ: Question = { id: qId, section: qSection, title: qTitle, text: qText, codeType: qType, marks: parseInt(qMarks) || 10, idealAnswerKey: qKey };
      const updatedQuestions = [...questions];
      if (currentQuestionIndex === -1 || currentQuestionIndex >= questions.length) {
          updatedQuestions.push(newQ);
          setQuestions(updatedQuestions);
          setCurrentQuestionIndex(updatedQuestions.length - 1);
      } else {
          updatedQuestions[currentQuestionIndex] = newQ;
          setQuestions(updatedQuestions);
      }
      return true;
  };

  const handleNextQuestion = () => {
      if (!commitCurrentQuestion()) { alert("Please fill title and text."); return; }
      const nextIndex = currentQuestionIndex + 1;
      if (nextIndex < questions.length) loadQuestionIntoForm(questions[nextIndex], nextIndex);
      else { setCurrentQuestionIndex(-1); clearQuestionForm(); }
  };

  const handlePrevQuestion = () => {
      commitCurrentQuestion();
      const prevIndex = currentQuestionIndex === -1 ? questions.length - 1 : currentQuestionIndex - 1;
      if (prevIndex >= 0) loadQuestionIntoForm(questions[prevIndex], prevIndex);
  };

  const handleJumpToQuestion = (index: number) => {
      commitCurrentQuestion();
      if (index >= 0 && index < questions.length) loadQuestionIntoForm(questions[index], index);
  };

  const handleAddNewQuestion = () => {
      commitCurrentQuestion();
      setCurrentQuestionIndex(-1);
      clearQuestionForm();
  };

  const handleRemoveCurrentQuestion = () => {
      if (currentQuestionIndex >= 0 && currentQuestionIndex < questions.length) {
          const newQs = questions.filter((_, i) => i !== currentQuestionIndex);
          setQuestions(newQs);
          if (newQs.length > 0) {
              const newIndex = Math.min(currentQuestionIndex, newQs.length - 1);
              loadQuestionIntoForm(newQs[newIndex], newIndex);
          } else {
              setCurrentQuestionIndex(-1);
              clearQuestionForm();
          }
      }
  };

  const handleSavePaper = async () => {
    if (qTitle.trim() && qText.trim()) commitCurrentQuestion();
    await new Promise(r => setTimeout(r, 100));
    if (!paperTitle) { alert("Please provide a paper title."); return; }
    let finalQuestions = [...questions];
    if (qTitle.trim() && qText.trim()) {
        const currentFormQ: Question = { id: qId, section: qSection, title: qTitle, text: qText, codeType: qType, marks: parseInt(qMarks) || 10, idealAnswerKey: qKey };
        if (currentQuestionIndex === -1) finalQuestions.push(currentFormQ);
        else finalQuestions[currentQuestionIndex] = currentFormQ;
    }
    if (finalQuestions.length === 0) { alert("Please add questions."); return; }

    const paper: QuestionPaper = {
      id: editingPaperId || `paper-${Date.now()}`,
      title: paperTitle,
      description: paperDesc,
      questions: finalQuestions,
      duration: paperDuration,
      createdAt: editingPaperId ? (papers.find(p => p.id === editingPaperId)?.createdAt || Date.now()) : Date.now()
    };

    if (editingPaperId) await db.updateQuestionPaper(paper);
    else await db.createQuestionPaper(paper);
    alert("Exam Paper Saved!");
    initPaperEditor(undefined);
    fetchData();
  };

  const handleAssign = async () => {
    if (!assignEmail || !assignPaperId) return;
    await db.assignExam(assignEmail, assignPaperId);
    setAssignStatus(`Assigned to ${assignEmail}`);
    setAssignEmail('');
    fetchData();
    setTimeout(() => setAssignStatus(''), 3000);
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'IN_PROGRESS': return <span className="bg-yellow-100 text-yellow-800 px-2 py-1 rounded-full text-xs">In Progress</span>;
      case 'SUBMITTED': return <span className="bg-blue-100 text-blue-800 px-2 py-1 rounded-full text-xs">Submitted</span>;
      case 'GRADED': return <span className="bg-green-100 text-green-800 px-2 py-1 rounded-full text-xs">Graded</span>;
      default: return <span className="bg-gray-100 text-gray-800 px-2 py-1 rounded-full text-xs">Not Started</span>;
    }
  };

  const renderManageExams = () => (
    <div className="grid md:grid-cols-4 gap-6">
        <div className="md:col-span-1 bg-white rounded-lg shadow p-4 h-fit max-h-screen overflow-y-auto">
            <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold text-lg">Exam Papers</h3>
