                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{sub?.aiEvaluation ? `${sub.aiEvaluation.totalScore} / ${sub.aiEvaluation.maxScore}` : '-'}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                    <button onClick={() => setSelectedCandidateId(candidate.id)} className="text-brand-600 hover:text-brand-900 mr-3">View</button>
                    <button onClick={() => handleResetSubmission(candidate.id, candidate.fullName)} className="text-orange-600 hover:text-orange-900 mr-3">Reset</button>
                    <button onClick={() => handleDeleteCandidate(candidate.id, candidate.fullName)} className="text-red-600 hover:text-red-900">Delete User</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div>
        <div className="mb-6 flex gap-4 border-b">
            <button className={`pb-2 px-4 font-medium ${activeTab === 'SUBMISSIONS' ? 'text-brand-600 border-b-2 border-brand-600' : 'text-gray-500 hover:text-gray-700'}`} onClick={() => setActiveTab('SUBMISSIONS')}>Submissions</button>
            <button className={`pb-2 px-4 font-medium ${activeTab === 'MANAGE_EXAMS' ? 'text-brand-600 border-b-2 border-brand-600' : 'text-gray-500 hover:text-gray-700'}`} onClick={() => setActiveTab('MANAGE_EXAMS')}>Manage Exams</button>
            <button className={`pb-2 px-4 font-medium ${activeTab === 'ASSIGN_EXAMS' ? 'text-brand-600 border-b-2 border-brand-600' : 'text-gray-500 hover:text-gray-700'}`} onClick={() => setActiveTab('ASSIGN_EXAMS')}>Assign Exams</button>
        </div>
        {activeTab === 'SUBMISSIONS' && renderSubmissions()}
        {activeTab === 'MANAGE_EXAMS' && renderManageExams()}
        {activeTab === 'ASSIGN_EXAMS' && renderAssign()}
    </div>
  );
};

