## components/CodeRunner.tsx

**Changes:** Added QA (Selenium, Cypress) and DevOps (Docker, K8s) tools to the dropdown.

```typescript
import React, { useState, useEffect, useRef } from 'react';
import { executeCodeWithAI } from '../services/gemini';

// Access global Prism object from CDN
declare const Prism: any;

interface CodeRunnerProps {
  code: string;
  onChange: (newCode: string) => void;
  language: string; // This is the DEFAULT language
}

const SUPPORTED_LANGUAGES = [
    { label: "--- Languages ---", value: "disabled-1" },
    { value: 'javascript', label: 'JavaScript' },
    { value: 'python', label: 'Python' },
    { value: 'java', label: 'Java' },
    { value: 'cpp', label: 'C++' },
    { value: 'csharp', label: 'C#' },
    { value: 'go', label: 'Go' },
    { value: 'rust', label: 'Rust' },
    { value: 'sql', label: 'SQL' },
    { label: "--- QA Tools ---", value: "disabled-2" },
    { value: 'selenium_java', label: 'Selenium (Java)' },
    { value: 'selenium_python', label: 'Selenium (Python)' },
    { value: 'cypress', label: 'Cypress (JS)' },
    { value: 'playwright', label: 'Playwright' },
    { value: 'cucumber', label: 'Cucumber/Gherkin' },
    { value: 'postman', label: 'Postman (JSON)' },
    { value: 'junit', label: 'JUnit/TestNG' },
    { label: "--- DevOps Tools ---", value: "disabled-3" },
    { value: 'docker', label: 'Docker (Dockerfile)' },
    { value: 'kubernetes', label: 'Kubernetes (YAML)' },
    { value: 'terraform', label: 'Terraform (HCL)' },
    { value: 'ansible', label: 'Ansible (YAML)' },
    { value: 'bash', label: 'Bash/Shell' },
    { value: 'jenkins', label: 'Jenkins (Groovy)' }
];

const CodeRunner: React.FC<CodeRunnerProps> = ({ code, onChange, language }) => {
  // Allow user to change language. Default to prop provided.
  const [selectedLanguage, setSelectedLanguage] = useState(language);

  const [output, setOutput] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isChecking, setIsChecking] = useState(false); // For AI validation
  const [highlightedCode, setHighlightedCode] = useState('');

  const preRef = useRef<HTMLPreElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // Sync state if prop changes (e.g. next question)
  useEffect(() => {
      setSelectedLanguage(language);
  }, [language]);

  // Handle Syntax Highlighting for Input based on selectedLanguage
  useEffect(() => {
    if (typeof Prism !== 'undefined') {
      let langClass = selectedLanguage.toLowerCase();
      // Map specialized tools to Prism classes
      if (langClass === 'c++') langClass = 'cpp';
      if (langClass === 'c#') langClass = 'csharp';

      // QA Mappings
      if (langClass === 'selenium_java' || langClass === 'junit') langClass = 'java';
      if (langClass === 'selenium_python') langClass = 'python';
      if (langClass === 'cypress' || langClass === 'playwright') langClass = 'javascript';
      if (langClass === 'cucumber') langClass = 'gherkin'; // Requires gherkin prism component
      if (langClass === 'postman') langClass = 'json';

      // DevOps Mappings
      if (langClass === 'docker') langClass = 'docker';
      if (langClass === 'kubernetes' || langClass === 'ansible') langClass = 'yaml';
      if (langClass === 'terraform') langClass = 'hcl'; // Terraform uses HCL
      if (langClass === 'jenkins') langClass = 'groovy';
      if (langClass === 'bash') langClass = 'bash';

      // Default to generic 'clike' or 'javascript' if grammar not found
      // If specialized grammar (like docker) is missing, it falls back to plain text often, 
      // but we can try to fallback to clike for basic coloring.
      const grammar = Prism.languages[langClass] || Prism.languages.javascript;

      if (grammar) {
        const html = Prism.highlight(code || '', grammar, langClass);
        setHighlightedCode(html);
      } else {
        setHighlightedCode(code.replace(/</g, "&lt;").replace(/>/g, "&gt;"));
      }
    } else {
      // Fallback if not a code language or Prism missing
      setHighlightedCode(code.replace(/</g, "&lt;").replace(/>/g, "&gt;"));
    }
  }, [code, selectedLanguage]);

  // Sync scroll between textarea and pre
  const handleScroll = (e: React.UIEvent<HTMLTextAreaElement>) => {
    if (preRef.current) {
      preRef.current.scrollTop = e.currentTarget.scrollTop;
      preRef.current.scrollLeft = e.currentTarget.scrollLeft;
    }
  };

  const handleRunCode = async () => {
    // If user selected JS, we can run locally. 
    // Otherwise use AI executor.
    if (selectedLanguage === 'javascript') {
        runJsLocally();
    } else {
        runWithAI();
    }
  };

  const runWithAI = async () => {
    setIsChecking(true);
    setOutput(null);
    setError(null);
    try {
      const result = await executeCodeWithAI(code, selectedLanguage);
      if (result.type === 'error') {
        setError(result.content);
      } else { // 'output'
        const outputContent = result.content.trim() === '' 
          ? `// ${selectedLanguage} code executed successfully with no output.`
          : result.content;
        setOutput(outputContent);
      }
    } catch(e: any) {
      setError(e.toString());
    } finally {
      setIsChecking(false);
    }
  };

  const runJsLocally = () => {
    setOutput(null);
    setError(null);

    const logs: string[] = [];
    const originalConsoleLog = console.log;

    // Intercept console.log
    console.log = (...args: any[]) => {
      logs.push(args.map(a => {
        if (typeof a === 'object') return JSON.stringify(a, null, 2);
        return String(a);
      }).join(' '));
    };

    try {
      // Execute unsafe code safely in a minimal scope
      // eslint-disable-next-line no-new-func
      const run = new Function(code);
      const result = run();

      if (result !== undefined) {
        if (typeof result === 'object') {
            logs.push(`> Return Value:\n${JSON.stringify(result, null, 2)}`);
        } else {
            logs.push(`> Return Value: ${String(result)}`);
        }
      }

      if (logs.length === 0) {
        logs.push("// Code executed successfully (No output).\n// Use console.log() to see results.");
      }

      setOutput(logs.join('\n'));
    } catch (e: any) {
      setError(e.toString());
    } finally {
      // Restore console.log
      console.log = originalConsoleLog;
    }
  };

  // Helper to highlight output logs (basic JSON highlighting)
  const getHighlightedOutput = (text: string) => {
    if (typeof Prism !== 'undefined') {
       const grammar = (text.trim().startsWith('{') || text.trim().startsWith('[')) 
          ? Prism.languages.json 
          : Prism.languages.javascript;

       return Prism.highlight(text, grammar, 'javascript');
    }
    return text;
  };

  const getFileName = () => {
      // Standard Langs
      if (selectedLanguage === 'javascript') return 'main.js';
      if (selectedLanguage === 'python') return 'script.py';
      if (selectedLanguage === 'java') return 'Main.java';
      if (selectedLanguage === 'cpp') return 'main.cpp';
      if (selectedLanguage === 'csharp') return 'Program.cs';
      if (selectedLanguage === 'sql') return 'query.sql';

      // QA Tools
      if (selectedLanguage.includes('selenium_java')) return 'SeleniumTest.java';
      if (selectedLanguage.includes('selenium_python')) return 'selenium_test.py';
      if (selectedLanguage === 'cypress') return 'spec.cy.js';
      if (selectedLanguage === 'playwright') return 'test.spec.ts';
      if (selectedLanguage === 'cucumber') return 'features.feature';
      if (selectedLanguage === 'postman') return 'collection.json';

      // DevOps Tools
      if (selectedLanguage === 'docker') return 'Dockerfile';
      if (selectedLanguage === 'kubernetes') return 'deployment.yaml';
      if (selectedLanguage === 'terraform') return 'main.tf';
      if (selectedLanguage === 'ansible') return 'playbook.yaml';
      if (selectedLanguage === 'bash') return 'script.sh';
      if (selectedLanguage === 'jenkins') return 'Jenkinsfile';

      return `script.${selectedLanguage.slice(0, 3)}`;
  }

  const getButtonContent = () => {
    if (selectedLanguage !== 'javascript') {
      return isChecking ? 'Checking...' : `Check Code`;
    }
    return 'Run (JS)';
  };

  return (
    <div className="border border-gray-300 rounded-md overflow-hidden bg-[#2d2d2d] text-white shadow-sm flex flex-col h-[500px]">
      {/* Toolbar */}
      <div className="flex justify-between items-center bg-[#1f1f1f] px-4 py-2 border-b border-gray-700 shrink-0">
        <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
                <span className="w-3 h-3 rounded-full bg-red-500"></span>
                <span className="w-3 h-3 rounded-full bg-yellow-500"></span>
                <span className="w-3 h-3 rounded-full bg-green-500"></span>
            </div>

            {/* Language Selector */}
            <select 
                value={selectedLanguage} 
                onChange={(e) => setSelectedLanguage(e.target.value)}
                className="bg-[#2d2d2d] text-gray-300 text-xs border border-gray-600 rounded px-2 py-1 outline-none focus:border-brand-500 max-w-[200px]"
            >
                {SUPPORTED_LANGUAGES.map(lang => (
                    <option key={lang.value} value={lang.value} disabled={lang.value.startsWith('disabled')}>
                        {lang.label}
                    </option>
                ))}
            </select>

            <span className="ml-2 text-xs font-mono text-gray-400 uppercase tracking-wider hidden md:inline">
                {getFileName()}
            </span>
        </div>

        <button
          onClick={handleRunCode}
          type="button"
          disabled={isChecking}
          title={`Execute ${selectedLanguage} code`}
          className="bg-brand-600 hover:bg-brand-500 text-white px-3 py-1.5 rounded text-xs font-bold transition-colors flex items-center gap-1.5 shadow-sm disabled:bg-gray-600 disabled:cursor-not-allowed"
        >
          <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
          {getButtonContent()}
        </button>
      </div>

      <div className="flex flex-col md:flex-row flex-1 min-h-0">
        {/* Editor Area */}
        <div className={`flex-1 relative group ${output || error || isChecking ? 'md:border-r border-gray-700' : ''} min-h-[250px]`}>

          <pre 
            ref={preRef}
            className="absolute inset-0 m-0 p-4 font-mono text-sm leading-6 whitespace-pre-wrap break-words pointer-events-none overflow-hidden"
            style={{ fontFamily: '"Fira Code", "Consolas", monospace' }}
            aria-hidden="true"
          >
            <code 
              className={`language-${selectedLanguage === 'c++' ? 'cpp' : selectedLanguage}`}
              dangerouslySetInnerHTML={{ __html: highlightedCode + '<br/>' }} 
            />
          </pre>

          <textarea
            ref={textareaRef}
            value={code}
            onChange={(e) => onChange(e.target.value)}
            onScroll={handleScroll}
            className="absolute inset-0 w-full h-full p-4 font-mono text-sm leading-6 bg-transparent text-transparent caret-white resize-none focus:outline-none overflow-auto"
            style={{ fontFamily: '"Fira Code", "Consolas", monospace' }}
            placeholder={`// Write your ${selectedLanguage} solution here...`}
            spellCheck={false}
            autoCapitalize="off"
            autoComplete="off"
          />
        </div>

        {/* Output Console */}
        {(output !== null || error !== null || isChecking) && (
          <div className="w-full md:w-2/5 bg-[#1e1e1e] flex flex-col min-h-[150px] border-t md:border-t-0 border-gray-700">
            <div className="bg-[#252526] px-3 py-1 text-[10px] uppercase tracking-wider text-gray-400 border-b border-gray-700 flex justify-between items-center shrink-0">
                <span>Console Output</span>
                <button onClick={() => {setOutput(null); setError(null);}} className="hover:text-white">&times;</button>
            </div>

            <div className="flex-1 p-3 overflow-auto font-mono text-xs">
                {isChecking && <div className="text-yellow-400">Executing code on remote server...</div>}
                {error ? (
                  <div className="text-red-400 whitespace-pre-wrap font-bold">
                    <span className="block mb-1 text-red-500">⚠ Error:</span>
                    {error}
                  </div>
                ) : (
                  <pre 
                    className="whitespace-pre-wrap text-gray-300"
                    dangerouslySetInnerHTML={{ 
                        __html: output ? (selectedLanguage === 'javascript' ? getHighlightedOutput(output) : output) : '' 
                    }} 
                  />
                )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CodeRunner;
