    if (this.useLocalStorage) {
        const submissions = this.getLS<ExamSubmission>(LS_KEYS.SUBMISSIONS);
        const existing = submissions.find(s => s.candidateId === candidateId);
        if (existing) return existing;

        const newSub: ExamSubmission = {
