    }

    const submissionsRef = collection(this.db, COLLECTIONS.SUBMISSIONS);
    const q = query(submissionsRef, where('candidateId', '==', candidateId));
    const snapshot = await getDocs(q);

    if (!snapshot.empty) {
        return snapshot.docs[0].data() as ExamSubmission;
