    const newSubmission: ExamSubmission = {
        candidateId,
        paperId,
        startTime: Date.now(),
        answers: {},
        proctorLogs: [],
        status: 'IN_PROGRESS'
    };
    await addDoc(submissionsRef, newSubmission);
    return newSubmission;
